INSERT INTO public.task_faqs (task_id, phase, question, answer) VALUES
('housing', 'phase-2', 'How do I avoid housing scams in Italy?', 'Never pay before visiting the property in person. Be wary of landlords who refuse to meet or show the property. Avoid wire transfers to unknown accounts. Check if the landlord owns the property (ask for documents). Use reputable platforms like Spotahome or HousingAnywhere that offer booking protection.'),
('housing', 'phase-2', 'What is Cessione di fabbricato and why do I need it?', 'Cessione di fabbricato is a declaration that your landlord must file with the local police within 48 hours of you moving in. It confirms your address and is required for your residence permit application. Without it, you cannot complete the permesso di soggiorno process.'),
('housing', 'phase-2', 'Which housing platforms are best for international students?', 'Spotahome and HousingAnywhere offer verified listings with booking protection - great for booking before arrival. Immobiliare.it and Idealista have more local listings but require more caution. Facebook groups like "Appartamenti Milano" or "Housing Milano Students" are useful but verify everything carefully.'),
('housing', 'phase-2', 'How much deposit should I expect to pay?', 'Typically 1-3 months rent as a security deposit (cauzione), plus the first month rent upfront. Some landlords also ask for an agency fee (usually one month rent) if you use an agency. Budget around €2000-4000 for initial housing costs in Milan.'),
('housing', 'phase-2', 'Can I find housing before arriving in Italy?', 'Yes, but be careful. Use platforms with booking protection like Spotahome or HousingAnywhere. Many students book temporary accommodation (Airbnb, hostel) for 2-4 weeks and search for permanent housing after arrival when they can visit properties in person.'),
('housing', 'phase-2', 'What type of rental contract should I look for as a student?', 'Look for "contratto transitorio" (transitional contract) which is designed for temporary needs like students. It typically lasts 1-18 months. Avoid informal arrangements without a proper contract as you need it for your residence permit and other official procedures.');